+  args?: string[];
+  env?: WatchRunParams["env"];
+  spawn: NonNullable<WatchRunParams["spawn"]>;
+}) => {
+  const watcher = Object.assign(new EventEmitter(), {
+    close: vi.fn(async () => {}),
+  });
+  const createWatcher = vi.fn(() => watcher);
